import Link from 'next/link';
import { MapPin, Star, TrendingUp, Info } from 'lucide-react';
import { College } from '@/types/college';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import CompareButton from '@/components/compare/CompareButton';
import CollegeImage from '@/components/college/CollegeImage';

interface CollegeCardProps {
  college: College;
  priority?: boolean;
}

export default function CollegeCard({ college, priority = false }: CollegeCardProps) {
  const formattedFees = new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0,
  }).format(college.fees);

  return (
    <article className="group flex h-full flex-col overflow-hidden rounded-2xl border border-gray-100 bg-white shadow-sm transition-all duration-300 hover:shadow-xl">
      <div className="relative h-44 w-full overflow-hidden sm:h-48">
        <CollegeImage
          collegeId={college.id}
          src={college.image}
          alt={`${college.name} campus`}
          type="campus"
          fill
          sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
          priority={priority}
          className="object-cover transition-transform duration-500 group-hover:scale-105"
        />
        <div className="absolute left-4 top-4 rounded-lg bg-white p-2 shadow-md">
          <div className="relative h-10 w-10">
            <CollegeImage
              collegeId={college.id}
              src={college.logo}
              alt={`${college.name} logo`}
              type="logo"
              fill
              sizes="40px"
              className="object-contain"
            />
          </div>
        </div>
        <div className="absolute right-4 top-4">
          <Badge
            variant={
              college.stream === 'Engineering'
                ? 'blue'
                : college.stream === 'Arts'
                  ? 'orange'
                  : 'green'
            }
          >
            {college.stream}
          </Badge>
        </div>
      </div>

      <div className="flex flex-grow flex-col p-4 sm:p-5">
        <div className="mb-2 flex items-start justify-between gap-2">
          <h3 className="line-clamp-2 min-h-[2.75rem] text-base font-bold leading-tight text-gray-900 sm:min-h-[3.5rem] sm:text-lg">
            {college.name}
          </h3>
          <div
            className="flex shrink-0 items-center rounded-md bg-green-50 px-2 py-1"
            aria-label={`Rating ${college.rating} out of 5`}
          >
            <Star className="mr-1 h-3.5 w-3.5 fill-current text-green-600" aria-hidden />
            <span className="text-sm font-bold text-green-700">{college.rating}</span>
          </div>
        </div>

        <div className="mb-4 flex items-center text-sm text-gray-500">
          <MapPin className="mr-1 h-3.5 w-3.5 shrink-0" aria-hidden />
          <span className="truncate">{college.location}</span>
        </div>

        <div className="mb-6 grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <p className="text-[10px] font-bold uppercase tracking-wider text-gray-400">Avg Fees</p>
            <p className="text-sm font-semibold text-gray-800">{formattedFees}</p>
          </div>
          <div className="space-y-1">
            <p className="text-[10px] font-bold uppercase tracking-wider text-gray-400">Placement</p>
            <div className="flex items-center">
              <TrendingUp className="mr-1 h-3 w-3 text-blue-500" aria-hidden />
              <p className="text-sm font-semibold text-gray-800">{college.placementPercentage}%</p>
            </div>
          </div>
        </div>

        <div className="mt-auto flex gap-2 border-t border-gray-50 pt-4">
          <Link href={`/college/${college.id}`} className="flex-1">
            <Button variant="outline" className="w-full py-2 text-xs font-semibold">
              <Info className="mr-1.5 h-3.5 w-3.5" aria-hidden />
              Details
            </Button>
          </Link>
          <CompareButton id={college.id} className="flex-1 py-2 text-xs font-semibold" />
        </div>
      </div>
    </article>
  );
}
