'use client';

import { useState, useEffect, useCallback } from 'react';
import { College, Stream } from '@/types/college';
import { getColleges } from '@/lib/data-service';
import { useDebounce } from './useDebounce';

export type SortOption = 'rating' | 'fees-asc' | 'fees-desc' | 'placement';

export const useColleges = () => {
  const [colleges, setColleges] = useState<College[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [search, setSearch] = useState('');
  const debouncedSearch = useDebounce(search, 300);
  const [stream, setStream] = useState<Stream | 'All'>('All');
  const [sortBy, setSortBy] = useState<SortOption>('rating');
  const [visibleCount, setVisibleCount] = useState(4);

  const fetchColleges = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getColleges({
        search: debouncedSearch,
        stream: stream === 'All' ? undefined : stream,
      });

      const sorted = [...data].sort((a, b) => {
        switch (sortBy) {
          case 'rating':
            return b.rating - a.rating;
          case 'fees-asc':
            return a.fees - b.fees;
          case 'fees-desc':
            return b.fees - a.fees;
          case 'placement':
            return b.placementPercentage - a.placementPercentage;
          default:
            return 0;
        }
      });

      setColleges(sorted);
      setError(null);
    } catch {
      setError('Failed to load colleges. Please try again later.');
    } finally {
      setLoading(false);
    }
  }, [debouncedSearch, stream, sortBy]);

  useEffect(() => {
    fetchColleges();
    setVisibleCount(4);
  }, [fetchColleges]);

  const loadMore = () => {
    setVisibleCount((prev) => prev + 4);
  };

  const hasMore = visibleCount < colleges.length;
  const isSearching = search !== debouncedSearch;

  return {
    colleges: colleges.slice(0, visibleCount),
    totalCount: colleges.length,
    loading: loading || isSearching,
    error,
    search,
    setSearch,
    stream,
    setStream,
    sortBy,
    setSortBy,
    loadMore,
    hasMore,
    retry: fetchColleges,
  };
};
